import org.apache.spark.sql.{DataFrame, SparkSession}
import org.apache.spark.sql.functions._
import scala.util.{Try, Success, Failure}

object SecureAnalyticsSqlApp {

  final case class ApiRequest(
    userId: String,
    query: String,
    limit: Option[Int] = Some(1000)
  )

  final case class ApiResponse(
    success: Boolean,
    message: String,
    columns: Seq[String] = Seq.empty,
    rows: Seq[Map[String, Any]] = Seq.empty
  )

  object QueryValidator {
    private val forbiddenPatterns = Seq(
      "(?i)\\bINSERT\\b".r,
      "(?i)\\bUPDATE\\b".r,
      "(?i)\\bDELETE\\b".r,
      "(?i)\\bMERGE\\b".r,
      "(?i)\\bDROP\\b".r,
      "(?i)\\bTRUNCATE\\b".r,
      "(?i)\\bALTER\\b".r,
      "(?i)\\bCREATE\\b".r,
      "(?i)\\bREPLACE\\b".r,
      "(?i)\\bCACHE\\b".r,
      "(?i)\\bUNCACHE\\b".r,
      "(?i)\\bREFRESH\\b".r,
      "(?i)\\bADD\\s+JAR\\b".r,
      "(?i)\\bADD\\s+FILE\\b".r,
      "(?i)\\bLIST\\s+JAR\\b".r,
      "(?i)\\bLIST\\s+FILE\\b".r,
      "(?i)\\bLOAD\\s+DATA\\b".r,
      "(?i)\\bANALYZE\\b".r,
      "(?i)\\bMSCK\\b".r,
      "(?i)\\bSET\\b".r,
      "(?i)\\bRESET\\b".r,
      "(?i);".r,
      "(?i)--".r,
      "(?i)/\\*".r,
      "(?i)\\*/".r
    )

    def validate(query: String): Either[String, String] = {
      val trimmed = Option(query).map(_.trim).getOrElse("")
      if (trimmed.isEmpty) Left("Query cannot be empty")
      else if (!trimmed.matches("(?is)^\\s*SELECT\\b.*") && !trimmed.matches("(?is)^\\s*WITH\\b.*"))
        Left("Only SELECT and WITH queries are allowed")
      else {
        val hit = forbiddenPatterns.find(_.findFirstIn(trimmed).nonEmpty)
        hit match {
          case Some(pattern) => Left(s"Query contains forbidden syntax: ${pattern.regex}")
          case None => Right(trimmed)
        }
      }
    }
  }

  object RowSerializer {
    def toMaps(df: DataFrame, maxRows: Int): Seq[Map[String, Any]] = {
      df.limit(maxRows).collect().toSeq.map { row =>
        row.schema.fields.zipWithIndex.map { case (field, idx) =>
          field.name -> row.get(idx)
        }.toMap
      }
    }
  }

  class AnalyticsService(spark: SparkSession, allowedViews: Set[String]) {

    def registerDataLakeViews(): Unit = {
      val users = spark.read.format("parquet").load("/data-lake/users")
      val events = spark.read.format("parquet").load("/data-lake/events")
      val orders = spark.read.format("parquet").load("/data-lake/orders")

      users.createOrReplaceTempView("users")
      events.createOrReplaceTempView("events")
      orders.createOrReplaceTempView("orders")
    }

    def handleRequest(request: ApiRequest): ApiResponse = {
      QueryValidator.validate(request.query) match {
        case Left(error) =>
          ApiResponse(success = false, message = error)

        case Right(validQuery) =>
          val referencedTables = extractReferencedTables(validQuery)
          val unauthorized = referencedTables.diff(allowedViews)
          if (unauthorized.nonEmpty) {
            ApiResponse(
              success = false,
              message = s"Unauthorized table/view access: ${unauthorized.toSeq.sorted.mkString(", ")}"
            )
          } else {
            executeReadOnlyQuery(validQuery, request.limit.getOrElse(1000))
          }
      }
    }

    private def executeReadOnlyQuery(query: String, limit: Int): ApiResponse = {
      Try {
        val analyzed = spark.sql(query)
        val safeDf = analyzed.limit(math.max(1, math.min(limit, 10000)))
        ApiResponse(
          success = true,
          message = "Query executed successfully",
          columns = safeDf.columns.toSeq,
          rows = RowSerializer.toMaps(safeDf, math.max(1, math.min(limit, 10000)))
        )
      } match {
        case Success(response) => response
        case Failure(ex) =>
          ApiResponse(success = false, message = s"Query execution failed: ${ex.getMessage}")
      }
    }

    private def extractReferencedTables(query: String): Set[String] = {
      val normalized = query.replaceAll("(?is)\\s+", " ")
      val regex = "(?i)\\b(?:FROM|JOIN)\\s+([a-zA-Z0-9_\\.]+)".r
      regex.findAllMatchIn(normalized).map(_.group(1).split("\\.").last.toLowerCase).toSet
    }
  }

